import{c as e,Q as a,j as r,m as s}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Auto Agentic Harness Engineering","description":"","frontmatter":{"url":"https://cobusgreyling.medium.com/auto-agentic-harness-engineering-b27a962fad9a","date":"2026-05-02T00:00:00.000Z","authors":"Cobus Greyling","source":"Medium (Cobus Greyling)","tags":["auto-harness","falsifiable-prediction","harness-portability","control-plane"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-02-cobus-greyling-auto-agentic-harness.md","filePath":"research/ai-articles/scored/2026-05-02-cobus-greyling-auto-agentic-harness.md","lastUpdated":1779894392000}'),n={name:"research/ai-articles/scored/2026-05-02-cobus-greyling-auto-agentic-harness.md"};function o(i,t,d,l,c,h){return a(),r("div",null,[...t[0]||(t[0]=[s(`<h1 id="auto-agentic-harness-engineering" tabindex="-1">Auto Agentic Harness Engineering <a class="header-anchor" href="#auto-agentic-harness-engineering" aria-label="Permalink to &quot;Auto Agentic Harness Engineering&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://cobusgreyling.medium.com/auto-agentic-harness-engineering-b27a962fad9a" target="_blank" rel="noreferrer">https://cobusgreyling.medium.com/auto-agentic-harness-engineering-b27a962fad9a</a><br><strong>作者</strong>：Cobus Greyling<br><strong>歸檔日期</strong>：2026-05-10</p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>Falsifiable prediction 方法論可立即採用</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>Harness 優化作為假設測試，新的思維框架</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>具體不對稱數字（33.7% vs 11.8%），但統計基礎不詳</td></tr><tr><td>D. 技術深度</td><td>6/10</td><td>概念清楚，實作細節有限</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>跨模型可移植</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.3/10</strong></td><td>8×0.3 + 7×0.2 + 7×0.2 + 6×0.15 + 8×0.15 = 7.30</td></tr></tbody></table><p><strong>整合決策</strong>：RULE — Falsifiable prediction 方法論整合進 Ratchet 決策流程<br><strong>整合位置</strong>：<code>research/agent-harness/RATCHET.md</code> + <code>.claude/refs/harness-design.md</code><br><strong>整合狀態</strong>：待實作</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Harness（tools + middleware + memory）比 prompts 更決定 agent 效能；進化的 system prompts 在脫離配套 infrastructure 後回退。引入「falsifiable prediction」框架：每次 harness 改動前先寫預測（「我預期這會改善 X by Y%」），改動後驗證。揭示 agent 不對稱性：33.7% 準確預測修復、11.8% 準確預測回歸。展示跨模型 harness 移植。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><h3 id="_1-harness-vs-prompts-的不對稱性" tabindex="-1">1. Harness vs Prompts 的不對稱性 <a class="header-anchor" href="#_1-harness-vs-prompts-的不對稱性" aria-label="Permalink to &quot;1. Harness vs Prompts 的不對稱性&quot;">​</a></h3><blockquote><p>&quot;We evolved system prompts for 6 weeks and improved accuracy by 23%. Then we stripped the harness and re-ran — accuracy dropped back to baseline. The prompt improvements were harness-dependent artifacts.&quot;</p></blockquote><p>Prompt 改善是 harness 依賴的工件（artifact），不是可遷移的能力。</p><h3 id="_2-falsifiable-prediction-框架" tabindex="-1">2. Falsifiable Prediction 框架 <a class="header-anchor" href="#_2-falsifiable-prediction-框架" aria-label="Permalink to &quot;2. Falsifiable Prediction 框架&quot;">​</a></h3><p><strong>改動前</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>預測：移除 step-back prompting 會讓推理任務準確率下降 15%</span></span>
<span class="line"><span>驗證方式：在 50 個推理任務上對比 A/B</span></span></code></pre></div><p><strong>改動後</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>實際結果：下降 8%（預測 15%）</span></span>
<span class="line"><span>學習：對推理的影響比預期小；對事實召回的影響更大（未預測到）</span></span></code></pre></div><h3 id="_3-agent-不對稱性-重要數據" tabindex="-1">3. Agent 不對稱性（重要數據） <a class="header-anchor" href="#_3-agent-不對稱性-重要數據" aria-label="Permalink to &quot;3. Agent 不對稱性（重要數據）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>預測類型</th><th>準確率</th><th>含義</th></tr></thead><tbody><tr><td>預測改善效果</td><td>33.7%</td><td>我們通常知道「哪裡可以改善」</td></tr><tr><td>預測回歸效果</td><td>11.8%</td><td>我們幾乎不知道「哪裡會被破壞」</td></tr></tbody></table><p><strong>結論</strong>：比「改善 harness」更重要的是「不要破壞 harness」。回歸是三倍難以預測的問題。</p><h3 id="_4-harness-跨模型可移植性" tabindex="-1">4. Harness 跨模型可移植性 <a class="header-anchor" href="#_4-harness-跨模型可移植性" aria-label="Permalink to &quot;4. Harness 跨模型可移植性&quot;">​</a></h3><p>設計良好的 harness 在 Claude Sonnet → Claude Opus → GPT-5 之間的移植損失 &lt; 5%。<br> 設計不良的 harness（依賴特定模型行為）移植損失 &gt; 40%。</p><p><strong>移植測試清單</strong>：</p><ol><li>移除所有模型特定的 workaround（「Claude 有時會...」的 hack）</li><li>對比在 3 個模型上的性能</li><li>損失 &gt; 10% = harness 過擬合特定模型行為</li></ol><hr><h2 id="對-cc-workspace-的映射" tabindex="-1">對 cc-workspace 的映射 <a class="header-anchor" href="#對-cc-workspace-的映射" aria-label="Permalink to &quot;對 cc-workspace 的映射&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>cc-workspace 應用</th><th>現狀</th></tr></thead><tbody><tr><td>Falsifiable prediction</td><td>每次改動 rules/hooks 前寫預測</td><td>❌ 未實作</td></tr><tr><td>11.8% 回歸預測準確率</td><td>解釋為何 <code>/deep-review</code> 如此重要</td><td>✅ 驗證現有實踐</td></tr><tr><td>Harness 移植測試</td><td>跨模型測試 (Haiku/Sonnet/Opus)</td><td>⚠️ 偶發性，非系統化</td></tr></tbody></table><p><strong>行動建議</strong>：</p><ul><li>在 <code>RATCHET.md</code> 加入 falsifiable prediction 步驟（改前寫預測）</li><li>建立 regression test checklist（參考 11.8% 不對稱性）</li></ul>`,31)])])}const u=e(n,[["render",o]]);export{g as __pageData,u as default};
